/*@ Extern Coq (array_count_increasing_steps_spec : list Z -> Z) */
/*@ Import Coq Require Import array_count_increasing_steps */

int array_count_increasing_steps(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == array_count_increasing_steps_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int cnt = 0;

    /*@ Inv
          0 <= i && i <= n &&
          (0 < n => i + 1 <= n) &&
          a == a@pre &&
          n == n@pre &&
          cnt == array_count_increasing_steps_spec(sublist(0, i + 1, l)) &&
          IntArray::full(a, n, l)
    */
    for (i = 0; i + 1 < n; ++i) {
        if (a[i] < a[i + 1]) {
            cnt++;
        }
    }

    return cnt;
}

